/**
 * Emits per-rule `.jinja` files for the render pipeline (feature 011).
 *
 * The YAML template format (`templates.yaml`) was retired in favor of
 * per-rule `.jinja` files — see ADR-0013 / spec 011 for design notes.
 * This file owns the two functions that drive that emission:
 *
 *   - `emitJinjaTemplates(config)` — pure function: walks the NodeMap,
 *     delegates to `translateToJinja` for each node, returns a Map
 *     keyed by rule kind (values include the `@generated` header).
 *   - `writeJinjaTemplates(emitted, outputDir)` — writes the Map to
 *     disk and removes any stale `.jinja` files whose rule kinds are
 *     no longer present.
 *
 * Translator-level logic (placeholder → `{{ var }}`, clause → `{% if %}`,
 * variant branching → `{% if variant == "..." %}`) lives in
 * `./jinja-translator.ts`. Template-walker logic (how a rule's
 * AssembledNode shape becomes a YAML-era template string in the first
 * place) lives on the `AssembledNode` class hierarchy in
 * `compiler/node-map.ts` — the translator calls `node.renderTemplate()`
 * to get that string, then translates it to Jinja.
 */

import * as fs from 'node:fs'
import { join } from 'node:path'
import type { NodeMap } from '../compiler/types.ts'
import { AssembledGroup } from '../compiler/node-map.ts'
import { compileWordMatcher } from '../compiler/common.ts'
import { translateToJinja } from './jinja-translator.ts'

export interface EmitTemplatesConfig {
    grammar: string
    nodeMap: NodeMap
    grammarSha?: string
}

export interface EmittedTemplates {
    bodies: Map<string, string>
}

const GENERATED_HEADER = '{# @generated by @sittir/codegen — do not edit. Source: packages/codegen/src/emitters/templates.ts #}'

/**
 * Emit one `.jinja` body per rule in the NodeMap. Returns a Map keyed
 * by rule kind; values are the full file contents (including the
 * `@generated` comment header).
 *
 * Rules without a template (leaves / keywords / tokens / supertypes /
 * enums / non-polymorph-form groups / multis) are skipped — the
 * renderer's fallback handles them.
 */
export function emitJinjaTemplates(config: EmitTemplatesConfig): EmittedTemplates {
    const { nodeMap } = config
    const wordMatcher = compileWordMatcher(nodeMap.word, nodeMap.rules ?? {})
    const bodies = new Map<string, string>()
    for (const [kind, node] of nodeMap.nodes) {
        // Hidden kinds (`_`-prefixed) are skipped unless they're
        // polymorphs — factories stamp the source kind for the
        // drilled target (ADR-0006 drillAs).
        if (kind.startsWith('_') && node.modelType !== 'polymorph') continue
        // Polymorph-form groups get their own file via the group
        // branch in the translator; avoid double emission when the
        // form kind is also registered at the top level.
        if (node instanceof AssembledGroup && node.parentKind) continue
        let body: string | null
        try {
            body = translateToJinja(node, nodeMap.rules ?? {}, wordMatcher ?? /\w/)
        } catch (err) {
            // Re-throw with grammar + kind context so the emitter caller
            // gets an actionable error message.
            const cause = err instanceof Error ? err.message : String(err)
            throw new Error(
                `emitJinjaTemplates: failed on ${config.grammar}/${kind}: ${cause}`,
            )
        }
        if (body === null) continue
        bodies.set(kind, `${GENERATED_HEADER}\n${body}`)
    }
    return { bodies }
}

/**
 * Write per-kind `.jinja` files to `outputDir`. Creates the directory
 * if it does not exist. After writing, scans the directory for any
 * `.jinja` files whose kind is not in `emitted` and removes them —
 * prevents stale files from accumulating across regenerations when a
 * rule is renamed or removed from the grammar.
 *
 * Preserves `.gitkeep` and non-`.jinja` files (README.md, etc.).
 */
export function writeJinjaTemplates(emitted: EmittedTemplates, outputDir: string): void {
    fs.mkdirSync(outputDir, { recursive: true })
    for (const [kind, body] of emitted.bodies) {
        fs.writeFileSync(join(outputDir, `${kind}.jinja`), body, 'utf-8')
    }
    // Stale-file cleanup — only touches `.jinja` files. Anything else
    // (`.gitkeep`, README) is left alone. A pre-existing `_meta.json`
    // from the short-lived sidecar era (prior to the joinby-filter
    // migration) is removed — the Jinja bodies carry every separator
    // now, so the sidecar is dead data.
    const existing = fs.readdirSync(outputDir)
    const legacyMeta = join(outputDir, '_meta.json')
    if (fs.existsSync(legacyMeta)) fs.rmSync(legacyMeta, { force: true })
    for (const name of existing) {
        if (!name.endsWith('.jinja')) continue
        const kind = name.slice(0, -'.jinja'.length)
        if (!emitted.bodies.has(kind)) {
            fs.rmSync(join(outputDir, name), { force: true })
        }
    }
}
